package com.cognizant.springlearn.dao;
import com.cognizant.springlearn.model.*; import com.cognizant.springlearn.service.exception.EmployeeNotFoundException; import org.springframework.stereotype.Repository; import java.util.*;
@Repository public class EmployeeDao { private static final List<Employee> EMPLOYEES = new ArrayList<>(); static { Department tech = new Department(1,"Technology"); EMPLOYEES.add(new Employee(1,"John",50000,true,tech,new ArrayList<>(Arrays.asList(new Skill(1,"Java"))))); EMPLOYEES.add(new Employee(2,"Jane",60000,true,new Department(2,"HR"),new ArrayList<>(Arrays.asList(new Skill(2,"Angular"))))); } public List<Employee> getAll(){ return EMPLOYEES; } public Employee get(int id){ return EMPLOYEES.stream().filter(e -> e.getId()==id).findFirst().orElseThrow(() -> new EmployeeNotFoundException(id)); } public Employee update(int id, Employee employee){ Employee current = get(id); current.setName(employee.getName()); current.setSalary(employee.getSalary()); current.setPermanent(employee.isPermanent()); current.setDepartment(employee.getDepartment()); current.setSkills(employee.getSkills()); return current; } public void delete(int id){ EMPLOYEES.remove(get(id)); } }
